    "js": "class Icon extends HTMLElement {\n\n   static props = {\n      name: { \n         type: 'string', \n         default: 'youtube', \n         required: false \n      },\n      size: { \n         type: 'string', \n         default: 'small' \n      },\n      color: { \n         type: 'string', \n         default: 'black' \n      },\n      iconStyle: { \n         type: 'string', \n         default: 'filled' \n      }\n   };\n\n   constructor(props) {\n      super();\n\n      slice.attachTemplate(this);\n      this.$icon = this;\n\n      slice.controller.setComponentProps(this, props);\n   }\n\n   get random() {\n      return this.classList;\n   }\n\n   set random(value) {}\n\n   init() {\n      // Static props ensure all properties have default values\n      // No need for manual default checking\n   }\n\n   get name() {\n      return this._name;\n   }\n\n   set name(value) {\n      // Remove previous icon class if exists\n      if (this._name && this._iconStyle) {\n         this.classList.remove(`slc-${styleTypes[this._iconStyle]}${this._name}`);\n      }\n      \n      this._name = value;\n      // Add new icon class\n      this.classList.add(`slc-${styleTypes[this._iconStyle]}${value}`);\n   }\n\n   get iconStyle() {\n      return this._iconStyle;\n   }\n\n   set iconStyle(value) {\n      if (value !== 'filled' && value !== 'outlined') value = 'filled';\n      \n      // Remove old style class\n      if (this._name && this._iconStyle) {\n         this.classList.remove(`slc-${styleTypes[this._iconStyle]}${this._name}`);\n      }\n\n      this._iconStyle = value;\n      \n      // Add new style class\n      if (this._name) {\n         this.classList.add(`slc-${styleTypes[this._iconStyle]}${this._name}`);\n      }\n   }\n\n   get size() {\n      return this._size;\n   }\n\n   set size(value) {\n      if (!value) return;\n      \n      let pixelValue = value;\n      switch (value) {\n         case 'small':\n            pixelValue = '16px';\n            break;\n         case 'medium':\n            pixelValue = '20px';\n            break;\n         case 'large':\n            pixelValue = '24px';\n            break;\n      }\n      this._size = pixelValue;\n      this.style.fontSize = pixelValue;\n   }\n\n   get color() {\n      return this._color;\n   }\n\n   set color(value) {\n      this._color = value;\n      this.style.color = value;\n   }\n}\n\nconst styleTypes = { outlined: 'out', filled: 'fil' };\nwindow.Icon = Icon;\ncustomElements.define('slice-icon', Icon);\n\nreturn Icon;",
